using System.ComponentModel.DataAnnotations;

namespace RecipeShare.Models;

public class Recipe
{
    public int Id { get; set; }

    [Required, StringLength(100)]
    public string Title { get; set; } = string.Empty;

    [Required]
    public string Category { get; set; } = string.Empty;

    [Required]
    public string Ingredients { get; set; } = string.Empty;

    [Required]
    public string Steps { get; set; } = string.Empty;

    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

using RecipeShare.Models;

namespace RecipeShare.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes =
    [
        new() { Id = 1, Title = "Bruschetta", Category = "appetizers", Ingredients = "Baguette
Tomatoes
Basil
Garlic
Olive oil", Steps = "1. Slice and toast baguette
2. Dice tomatoes with garlic and basil
3. Drizzle with olive oil
4. Spoon mixture onto bread", AverageRating = 4.2, RatingCount = 5 },
        new() { Id = 2, Title = "Stuffed Mushrooms", Category = "appetizers", Ingredients = "Button mushrooms
Cream cheese
Garlic
Breadcrumbs
Parsley", Steps = "1. Remove mushroom stems
2. Mix cream cheese, garlic, and breadcrumbs
3. Fill caps with mixture
4. Bake at 375°F for 20 minutes", AverageRating = 4.5, RatingCount = 8 },
        new() { Id = 3, Title = "Spaghetti Carbonara", Category = "main-courses", Ingredients = "Spaghetti
Pancetta
Eggs
Parmesan
Black pepper", Steps = "1. Cook spaghetti al dente
2. Fry pancetta until crispy
3. Whisk eggs with parmesan
4. Toss hot pasta with pancetta, then egg mixture
5. Season with black pepper", AverageRating = 4.8, RatingCount = 12 },
        new() { Id = 4, Title = "Chicken Stir Fry", Category = "main-courses", Ingredients = "Chicken breast
Bell peppers
Soy sauce
Ginger
Rice", Steps = "1. Slice chicken into strips
2. Stir fry chicken with ginger
3. Add sliced peppers
4. Add soy sauce
5. Serve over rice", AverageRating = 4.0, RatingCount = 6 },
        new() { Id = 5, Title = "Chocolate Lava Cake", Category = "desserts", Ingredients = "Dark chocolate
Butter
Eggs
Sugar
Flour", Steps = "1. Melt chocolate and butter
2. Whisk eggs and sugar
3. Fold in chocolate mixture and flour
4. Bake at 425°F for 12 minutes
5. Invert onto plate and serve immediately", AverageRating = 4.9, RatingCount = 15 },
        new() { Id = 6, Title = "Tiramisu", Category = "desserts", Ingredients = "Ladyfingers
Mascarpone
Espresso
Cocoa powder
Eggs
Sugar", Steps = "1. Whisk egg yolks with sugar
2. Fold in mascarpone
3. Dip ladyfingers in espresso
4. Layer ladyfingers and cream
5. Dust with cocoa powder
6. Refrigerate 4 hours", AverageRating = 4.7, RatingCount = 10 },
    ];

    private int _nextId = 7;

    public List<Recipe> GetByCategory(string category)
    {
        return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    public Recipe? GetById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public void Add(Recipe recipe)
    {
        recipe.Id = _nextId++;
        _recipes.Add(recipe);
    }

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is null || stars < 1 || stars > 5) return;

        var totalStars = recipe.AverageRating * recipe.RatingCount + stars;
        recipe.RatingCount++;
        recipe.AverageRating = totalStars / recipe.RatingCount;
    }

    public IReadOnlyList<string> GetCategories() => ["appetizers", "main-courses", "desserts"];
}

