@page "/recipes"
@page "/recipes/{Category}"
@inject RecipeShare.Services.RecipeService RecipeService

<PageTitle>Recipes - @DisplayCategory</PageTitle>

<h1>@DisplayCategory Recipes</h1>

@if (string.IsNullOrEmpty(Category))
{
    <p>Select a category to browse recipes:</p>
    <ul>
        <li><a href="recipes/appetizers">🥗 Appetizers</a></li>
        <li><a href="recipes/main-courses">🍝 Main Courses</a></li>
        <li><a href="recipes/desserts">🍰 Desserts</a></li>
    </ul>
}
else if (Recipes.Count == 0)
{
    <p>No recipes found in this category.</p>
}
else
{
    <div class="row">
        @foreach (var recipe in Recipes)
        {
            <div class="col-md-6 mb-3">
                <div class="card">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text text-muted">
                            ⭐ @recipe.AverageRating.ToString("F1") (@recipe.RatingCount ratings)
                        </p>
                        <a href="recipe/@recipe.Id" class="btn btn-primary btn-sm">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter]
    public string? Category { get; set; }

    private List<RecipeShare.Models.Recipe> Recipes { get; set; } = [];

    private string DisplayCategory => Category?.Replace("-", " ") ?? "All";

    protected override void OnParametersSet()
    {
        Recipes = string.IsNullOrEmpty(Category)
            ? []
            : RecipeService.GetByCategory(Category);
    }
}

@page "/recipe/{Id:int}"
@inject RecipeShare.Services.RecipeService RecipeService

@if (Recipe is null)
{
    <PageTitle>Recipe Not Found</PageTitle>
    <h1>Recipe Not Found</h1>
    <p>Sorry, we couldn't find that recipe.</p>
}
else
{
    <PageTitle>@Recipe.Title - RecipeShare</PageTitle>

    <h1>@Recipe.Title</h1>
    <p class="text-muted">Category: @Recipe.Category.Replace("-", " ")</p>

    <StarRating RecipeId="Recipe.Id" CurrentRating="Recipe.AverageRating" RatingCount="Recipe.RatingCount" />

    <h3 class="mt-4">Ingredients</h3>
    <ul>
        @foreach (var ingredient in Recipe.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries))
        {
            <li>@ingredient</li>
        }
    </ul>

    <h3>Steps</h3>
    <ol>
        @foreach (var step in Recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
        {
            <li>@StripNumberPrefix(step)</li>
        }
    </ol>

    <a href="recipes/@Recipe.Category" class="btn btn-outline-secondary mt-3">← Back to category</a>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private RecipeShare.Models.Recipe? Recipe { get; set; }

    protected override void OnParametersSet()
    {
        Recipe = RecipeService.GetById(Id);
    }

    private static string StripNumberPrefix(string step)
    {
        var trimmed = step.TrimStart();
        var dotIndex = trimmed.IndexOf(". ");
        if (dotIndex > 0 && dotIndex <= 3 && int.TryParse(trimmed[..dotIndex], out _))
        {
            return trimmed[(dotIndex + 2)..];
        }
        return trimmed;
    }
}

@rendermode InteractiveServer
@inject RecipeShare.Services.RecipeService RecipeService

<div class="my-3">
    <span class="me-2">Rate this recipe:</span>
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span role="button" @onclick="() => SubmitRating(star)"
              style="font-size: 1.5rem; cursor: pointer; color: @(star <= DisplayRating ? "gold" : "#ccc");">
            ★
        </span>
    }
    <span class="ms-2 text-muted">
        @CurrentRating.ToString("F1") avg (@RatingCount ratings)
    </span>
    @if (Submitted)
    {
        <span class="ms-2 text-success">✓ Thanks for rating!</span>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double CurrentRating { get; set; }
    [Parameter] public int RatingCount { get; set; }

    private int DisplayRating { get; set; }
    private bool Submitted { get; set; }

    private void SubmitRating(int stars)
    {
        RecipeService.AddRating(RecipeId, stars);
        var recipe = RecipeService.GetById(RecipeId);
        if (recipe is not null)
        {
            CurrentRating = recipe.AverageRating;
            RatingCount = recipe.RatingCount;
        }
        DisplayRating = stars;
        Submitted = true;
    }
}

@page "/submit"
@rendermode InteractiveServer
@inject RecipeShare.Services.RecipeService RecipeService
@using RecipeShare.Models

<PageTitle>Submit a Recipe - RecipeShare</PageTitle>

<h1>Submit a Recipe</h1>

@if (SubmittedSuccessfully)
{
    <div class="alert alert-success">
        <strong>Recipe submitted!</strong> Your recipe "@Model.Title" has been added.
        <a href="recipe/@SubmittedId">View it here</a>.
    </div>
    <button class="btn btn-primary" @onclick="Reset">Submit Another</button>
}
else
{
    <EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" class="form-control" @bind-Value="Model.Title" />
            <ValidationMessage For="() => Model.Title" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" class="form-select" @bind-Value="Model.Category">
                <option value="">-- Select a category --</option>
                <option value="appetizers">Appetizers</option>
                <option value="main-courses">Main Courses</option>
                <option value="desserts">Desserts</option>
            </InputSelect>
            <ValidationMessage For="() => Model.Category" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" class="form-control" rows="5" @bind-Value="Model.Ingredients" />
            <ValidationMessage For="() => Model.Ingredients" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps (one per line)</label>
            <InputTextArea id="steps" class="form-control" rows="5" @bind-Value="Model.Steps" />
            <ValidationMessage For="() => Model.Steps" />
        </div>

        <button type="submit" class="btn btn-success">Submit Recipe</button>
    </EditForm>
}

@code {
    private Recipe Model { get; set; } = new();
    private bool SubmittedSuccessfully { get; set; }
    private int SubmittedId { get; set; }

    private void HandleSubmit()
    {
        RecipeService.Add(Model);
        SubmittedId = Model.Id;
        SubmittedSuccessfully = true;
    }

    private void Reset()
    {
        Model = new();
        SubmittedSuccessfully = false;
    }
}

